mapper.select:
SELECT e.emp_no AS empNo, e.name AS empName, d.name AS deptName, e.dept_id AS deptId, e.position AS position,
/* 성과 0차: 본인 점수 합산 */ (SELECT SUM(a.score) FROM eval_answer_52 a JOIN eval_target_mapping_52 m2 ON a.mapping_id = m2.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 0 AND m2.eval_type_id = 2 ) AS perfSelf,
/* 성과 1차: 부서장 점수 합산 */ (SELECT SUM(a.score) FROM eval_answer_52 a JOIN eval_target_mapping_52 m2 ON a.mapping_id = m2.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 1 AND m2.eval_type_id = 2 ) AS perfFirst,
CASE ISNULL(pm.status, -1) WHEN 0 THEN '본인평가중' WHEN 1 THEN '1차평가대기' WHEN 2 THEN '평가완료' ELSE '-' END AS perfStatus,
/* 역량 0차: 본인 점수 (배점 × 등급배수) */ (SELECT SUM(a.score * q.weight) FROM eval_answer_52 a JOIN eval_target_mapping_52 m2 ON a.mapping_id = m2.id JOIN eval_question_52 q ON a.question_id = q.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 0 AND m2.eval_type_id = 3 ) AS compSelf,
/* 역량 1차: 부서장 점수 (배점 × 등급배수) */ (SELECT SUM(a.score * q.weight) FROM eval_answer_52 a JOIN eval_target_mapping_52 m2 ON a.mapping_id = m2.id JOIN eval_question_52 q ON a.question_id = q.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 1 AND m2.eval_type_id = 3 ) AS compFirst,
CASE ISNULL(cm.status, -1) WHEN 0 THEN '본인평가중' WHEN 1 THEN '1차평가대기' WHEN 2 THEN '평가완료' ELSE '-' END AS compStatus,
/* 종합점수 = 성과1차 × 성과가중치 + 역량1차 × 역량가중치 */ ( SELECT ISNULL( (SELECT ISNULL(SUM(a.score), 0) FROM eval_answer_52 a JOIN eval_target_mapping_52 m2 ON a.mapping_id = m2.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 1 AND m2.eval_type_id = 2 ) * ISNULL(w2.weight, 50) / 100.0 + (SELECT ISNULL(SUM(a.score * q.weight), 0) FROM eval_answer_52 a JOIN eval_target_mapping_52 m2 ON a.mapping_id = m2.id JOIN eval_question_52 q ON a.question_id = q.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 1 AND m2.eval_type_id = 3 ) * ISNULL(w3.weight, 50) / 100.0 , 0) FROM (SELECT 1 AS dummy) AS t LEFT JOIN dept_eval_weight_52 w2 ON w2.dept_id = e.dept_id AND w2.type_id = 2 LEFT JOIN dept_eval_weight_52 w3 ON w3.dept_id = e.dept_id AND w3.type_id = 3 ) AS totalScore,
fr.grade AS totalGrade, fr.grade AS confirmedGrade, CASE fr.status WHEN 1 THEN '확정' ELSE '미확정' END AS confirmStatus, fr.reason AS reason, fr.weight_ratio AS weightRatio
FROM employee_52 e JOIN department_52 d ON e.dept_id = d.id
LEFT JOIN eval_target_mapping_52 pm ON pm.evaluatee_no = e.emp_no AND pm.step = 0 AND pm.eval_type_id = 2
LEFT JOIN eval_target_mapping_52 cm ON cm.evaluatee_no = e.emp_no AND cm.step = 0 AND cm.eval_type_id = 3
LEFT JOIN final_result_52 fr ON fr.emp_no = e.emp_no AND fr.year = #{year}
WHERE e.status = 'ACTIVE' AND e.position = '부서원' AND pm.id IS NOT NULL AND cm.id IS NOT NULL
AND e.emp_no = #{empNo}
AND e.dept_id = #{deptId}
ORDER BY d.name, e.emp_no

SELECT e.emp_no AS empNo, e.name AS empName, d.name AS deptName, e.dept_id AS deptId, e.position AS position,
/* 다면 평균점수: 평가자별 합산 점수의 평균 */ ( SELECT AVG(CAST(sub.total AS FLOAT)) FROM ( SELECT m2.id, SUM(a.score) AS total FROM eval_answer_52 a JOIN eval_target_mapping_52 m2 ON a.mapping_id = m2.id JOIN eval_type_52 t2 ON m2.eval_type_id = t2.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 1 AND m2.status = 2 AND t2.name LIKE '%다면%' GROUP BY m2.id ) AS sub ) AS multiAvgScore,
/* 다면 상태: status=2(완료) 수 / 전체 평가자 수(step=1) */ ( SELECT CASE WHEN COUNT(*) = 0 THEN '평가전' WHEN SUM(CASE WHEN m2.status = 2 THEN 1 ELSE 0 END) = 0 THEN CONCAT('평가중 (0/', COUNT(*), '명)') WHEN SUM(CASE WHEN m2.status = 2 THEN 1 ELSE 0 END) = COUNT(*) THEN '평가완료' ELSE CONCAT('평가중 (', SUM(CASE WHEN m2.status = 2 THEN 1 ELSE 0 END), '/', COUNT(*), '명)') END FROM eval_target_mapping_52 m2 JOIN eval_type_52 t2 ON m2.eval_type_id = t2.id WHERE m2.evaluatee_no = e.emp_no AND m2.step = 1 AND t2.name LIKE '%다면%' ) AS multiStatus,
fr.grade AS totalGrade, fr.grade AS confirmedGrade, CASE fr.status WHEN 1 THEN '확정' ELSE '미확정' END AS confirmStatus, fr.reason AS reason, fr.weight_ratio AS weightRatio
FROM employee_52 e JOIN department_52 d ON e.dept_id = d.id
LEFT JOIN final_result_52 fr ON fr.emp_no = e.emp_no AND fr.year = #{year}
WHERE e.status = 'ACTIVE' AND e.position = '부서장'
AND e.emp_no = #{empNo}
AND e.dept_id = #{deptId}
ORDER BY d.name, e.emp_no

mapper.update:
UPDATE final_result_52
SET status     = 1,
    updated_at = GETDATE(),
    updated_by = #{updatedBy}
WHERE emp_no = #{empNo} AND year = #{year}
